   116→    if (searchTerm && !train.trainNumber.toLowerCase().includes(searchTerm.toLowerCase())) {
   117→      return false;
   118→    }
   119→    if (fleetIds.length > 0 && !fleetIds.includes(train.fleetId)) {
   120→      return false;
   121→    }
