   238→              pmCount={pmCountByTrain[train.id] || 0}
   239→              onSelect={handleSelectTrain}
   240→            />
   241→          ))
   242→        )}
   243→      </div>
   244→
   245→      {/* Fleet Summary */}
   246→      <div style={{
