   252→          <div style={{ textAlign: 'center' }}>
   253→            <div style={{ color: FITNESS_STATUS_COLORS.FIT, fontWeight: 600 }}>
   254→              {fleetState.trains.filter(t => t.fitnessStatus === 'FIT').length}
   255→            </div>
   256→            <div className={Classes.TEXT_MUTED}>FIT</div>
   257→          </div>
   258→          <div style={{ textAlign: 'center' }}>
   259→            <div style={{ color: FITNESS_STATUS_COLORS.RESTRICTED, fontWeight: 600 }}>
   260→              {fleetState.trains.filter(t => t.fitnessStatus === 'RESTRICTED').length}
   261→            </div>
   262→            <div className={Classes.TEXT_MUTED}>RESTR</div>
   263→          </div>
   264→          <div style={{ textAlign: 'center' }}>
   265→            <div style={{ color: FITNESS_STATUS_COLORS.GROUNDED, fontWeight: 600 }}>
   266→              {fleetState.trains.filter(t => t.fitnessStatus === 'GROUNDED').length}
   267→            </div>
   268→            <div className={Classes.TEXT_MUTED}>GRND</div>
   269→          </div>
   270→        </div>
   271→      </div>
   272→    </div>
   273→  );
   274→}
