/**
 * Fleet Slice
 *
 * State management for fleet, train, depot, and route data.
 * Uses @belt/tools createSlice for reactive state.
 *
 * @see specs/006-user-interface.md Section 6.4
 */

import { createSlice, createAsyncSlice } from '@belt/tools';
import type {
  Train,
  Fleet,
  Depot,
  Route,
  TrainFilters,
  SortOptions,
  FitnessStatus,
} from '../types';

// =============================================================================
// Fleet Slice State
// =============================================================================

export interface FleetSliceState {
  fleets: Fleet[];
  trains: Train[];
  depots: Depot[];
  routes: Route[];
  selectedTrainId: string | null;
  selectedFleetId: string | null;
  filters: TrainFilters;
  sort: SortOptions;
  lastUpdated: number | null;
  [key: string]: unknown;
}

const initialFleetState: FleetSliceState = {
  fleets: [],
  trains: [],
  depots: [],
  routes: [],
  selectedTrainId: null,
  selectedFleetId: null,
  filters: {
    fleetIds: [],
    fitnessStatuses: [],
    depotIds: [],
    searchTerm: '',
  },
  sort: {
    field: 'trainNumber',
    direction: 'asc',
  },
  lastUpdated: null,
};

export const fleetSlice = createSlice({
  id: 'fleet',
  initial: initialFleetState,
  cache: { policy: 'session' },
  reducers: {
    // Fleet operations
    setFleets: (s, fleets: Fleet[]) => {
      const state = s as FleetSliceState;
      state.fleets = fleets;
      state.lastUpdated = Date.now();
    },

    // Train operations
    setTrains: (s, trains: Train[]) => {
      const state = s as FleetSliceState;
      state.trains = trains;
      state.lastUpdated = Date.now();
    },

    updateTrain: (s, train: Partial<Train> & { id: string }) => {
      const state = s as FleetSliceState;
      const index = state.trains.findIndex((t) => t.id === train.id);
      if (index !== -1) {
        state.trains[index] = { ...state.trains[index], ...train };
        state.lastUpdated = Date.now();
      }
    },

    updateTrainFitness: (
      s,
      payload: { trainId: string; status: FitnessStatus; notes?: string }
    ) => {
      const state = s as FleetSliceState;
      const train = state.trains.find((t) => t.id === payload.trainId);
      if (train) {
        train.fitnessStatus = payload.status;
        if (payload.notes !== undefined) {
          train.fitnessNotes = payload.notes;
        }
        state.lastUpdated = Date.now();
      }
    },

    updateTrainMileage: (s, payload: { trainId: string; mileageKm: number }) => {
      const state = s as FleetSliceState;
      const train = state.trains.find((t) => t.id === payload.trainId);
      if (train) {
        train.currentMileageKm = payload.mileageKm;
        state.lastUpdated = Date.now();
      }
    },

    // Depot operations
    setDepots: (s, depots: Depot[]) => {
      const state = s as FleetSliceState;
      state.depots = depots;
      state.lastUpdated = Date.now();
    },

    // Route operations
    setRoutes: (s, routes: Route[]) => {
      const state = s as FleetSliceState;
      state.routes = routes;
      state.lastUpdated = Date.now();
    },

    // Selection
    selectTrain: (s, trainId: string | null) => {
      const state = s as FleetSliceState;
      state.selectedTrainId = trainId;
    },

    selectFleet: (s, fleetId: string | null) => {
      const state = s as FleetSliceState;
      state.selectedFleetId = fleetId;
    },

    clearSelection: (s) => {
      const state = s as FleetSliceState;
      state.selectedTrainId = null;
      state.selectedFleetId = null;
    },

    // Filtering
    setFilters: (s, filters: Partial<TrainFilters>) => {
      const state = s as FleetSliceState;
      state.filters = { ...state.filters, ...filters };
    },

    setFleetFilter: (s, fleetIds: string[]) => {
      const state = s as FleetSliceState;
      state.filters.fleetIds = fleetIds;
    },

